// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_pubmed === false) return [{ json: { _source: 'pubmed', count: 0, _disabled_by_user: true } }];

// PUBMED COUNT - juste retmax=0 pour avoir le total
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.pubmed_query || '');
const PROXY = 'http://host.docker.internal:3456';

if (!query) {
  return [{ json: { _source: 'pubmed', count: 0, query: '' } }];
}

try {
  const url = `https://eutils.ncbi.nlm.nih.gov/entrez/eutils/esearch.fcgi?db=pubmed&term=${query}&retmax=0&retmode=json`;
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: PROXY + '?url=' + encodeURIComponent(url),
    timeout: 30000
  });
  const count = parseInt((resp.esearchresult || {}).count || '0');
  console.log('PubMed count: ' + count);
  return [{ json: { _source: 'pubmed', count, query: input.pubmed_query } }];
} catch(e) {
  console.log('PubMed count error: ' + e.message);
  return [{ json: { _source: 'pubmed', count: 0, error: e.message } }];
}

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_openalex === false) return [{ json: { _source: 'openalex', count: 0, _disabled_by_user: true } }];

// OPENALEX COUNT - per-page=1 pour avoir meta.count
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.openalex_query || '');
var __dY1 = parseInt(input.date_start) || 0, __dY2 = parseInt(input.date_end) || 0; // R4_COUNT_DATES_v1
var __dsuf = (__dY1 && __dY2) ? ('&filter=from_publication_date:' + __dY1 + '-01-01,to_publication_date:' + __dY2 + '-12-31') : '';
const PROXY = 'http://host.docker.internal:3456';

if (!query) {
  return [{ json: { _source: 'openalex', count: 0, query: '' } }];
}

// OPENALEX_COUNT_RETRY_v1 - OpenAlex 503 intermittent cote serveur -> 2 tentatives
const url = `https://api.openalex.org/works?search=${query}${__dsuf}&per-page=1&select=id&mailto=ultralab@review.org`;
let __last = null;
for (let __try = 0; __try < 2; __try++) {
  try {
    const resp = await this.helpers.httpRequest({ method: 'GET', url: PROXY + '?url=' + encodeURIComponent(url), timeout: 60000 });
    const count = parseInt((resp.meta || {}).count || '0');
    console.log('OpenAlex count: ' + count + (__try ? ' (retry)' : ''));
    return [{ json: { _source: 'openalex', count, query: input.openalex_query } }];
  } catch(e) {
    __last = e;
    if (__try === 0) { await new Promise(function(r){ setTimeout(r, 1500); }); }
  }
}
var __m = /timeout|50[23]|ECONN|EAI_AGAIN/i.test(String((__last && __last.message) || '')) ? 'OpenAlex temporairement indisponible (erreur 503 de leur serveur) ou requete trop large - reessayez, ou affinez avec des dates / des termes' : ((__last && __last.message) || 'erreur inconnue');
console.log('OpenAlex count error: ' + __m);
return [{ json: { _source: 'openalex', count: 0, error: __m } }];

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_crossref === false) return [{ json: { _source: 'crossref', count: 0, _disabled_by_user: true } }];

// CROSSREF COUNT - rows=0 pour avoir message.total-results
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.crossref_query || '');
var __dY1 = parseInt(input.date_start) || 0, __dY2 = parseInt(input.date_end) || 0; // R4_COUNT_DATES_v1
var __dsuf = (__dY1 && __dY2) ? ('&filter=from-pub-date:' + __dY1 + '-01-01,until-pub-date:' + __dY2 + '-12-31') : '';
const PROXY = 'http://host.docker.internal:3456';

if (!query) {
  return [{ json: { _source: 'crossref', count: 0, query: '' } }];
}

try {
  const url = `https://api.crossref.org/works?query=${query}${__dsuf}&rows=0&mailto=ultralab@review.org`;
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: PROXY + '?url=' + encodeURIComponent(url),
    timeout: 30000
  });
  const count = parseInt((resp.message || {})['total-results'] || '0');
  console.log('Crossref count: ' + count);
  return [{ json: { _source: 'crossref', count, query: input.crossref_query } }];
} catch(e) {
  console.log('Crossref count error: ' + e.message);
  return [{ json: { _source: 'crossref', count: 0, error: e.message } }];
}

// Combine les counts des 7 sources en un seul JSON avec total et warnings
const items = $input.all().map(i => i.json);
const counts = { pubmed: 0, openalex: 0, crossref: 0, semanticscholar: 0, doaj: 0, base: 0, lens: 0, sciencedirect: 0, clinicaltrials: 0 };
const errors = {};

for (const item of items) {
  const src = item._source;
  if (src && counts[src] !== undefined) {
    counts[src] = item.count || 0;
    if (item.error) errors[src] = item.error;
  }
}

const total = counts.pubmed + counts.openalex + counts.crossref + counts.semanticscholar + counts.doaj + counts.base + counts.lens + counts.sciencedirect + counts.clinicaltrials;
const warnings = [];

if (total === 0) {
  warnings.push('Aucun resultat trouve sur les 8 bases. Verifiez votre equation.');
}
if (total > 10000) {
  warnings.push('Plus de 10 000 resultats. Le traitement risque de saturer la RAM. Pensez a poser un cap.');
}
if (total > 50000) {
  warnings.push('CRITIQUE : plus de 50 000 resultats. Tres fortement deconseille sans cap strict.');
}
if (Object.keys(errors).length > 0) {
  warnings.push('Erreurs API : ' + JSON.stringify(errors));
}

console.log('Count summary: pubmed=' + counts.pubmed + ' openalex=' + counts.openalex + ' crossref=' + counts.crossref + ' semanticscholar=' + counts.semanticscholar + ' doaj=' + counts.doaj + ' base=' + counts.base + ' lens=' + counts.lens + ' sciencedirect=' + counts.sciencedirect + ' total=' + total);

return [{ json: {
  action: 'count',
  success: true,
  pubmed_count: counts.pubmed,
  openalex_count: counts.openalex,
  crossref_count: counts.crossref,
  semanticscholar_count: counts.semanticscholar,
  doaj_count: counts.doaj,
  base_count: counts.base,
  lens_count: counts.lens,
  sciencedirect_count: counts.sciencedirect,
  clinicaltrials_count: counts.clinicaltrials,
  total,
  warnings,
  errors
}}];

// MODULE_DELEGATE_SEARCH_v1

// GENERATE NBIB + SAVE FILE
// Format MEDLINE/nbib :
//   TAG - VALUE
//   Article separator : ligne vide
//
// Tags utilises :
//   PMID, PT (publication type), TI, AU, FAU, DP (date), TA (journal abbrev),
//   JT (journal full), AB (abstract), AID (article ID = doi), VI (volume),
//   IP (issue), PG (pages), LID (location ID), OWN (owner), STAT
const fs = require('fs');
const path = require('path');

const allItems = $input.all().map(i => i.json).filter(a => !a._empty);
const inputParams = $('Extract Params').first().json;
const capGlobal = parseInt(inputParams.cap_global) || 0;
const unlimited = inputParams.unlimited === true;

// PERSOURCE_CAP_v1 - honore les caps par base (les fetch paginent par blocs de ~200 et ne tronquent pas au cap exact)
if (!unlimited) {
  var __capMap = { pubmed: parseInt(inputParams.cap_pubmed)||0, openalex: parseInt(inputParams.cap_openalex)||0, crossref: parseInt(inputParams.cap_crossref)||0, semanticscholar: parseInt(inputParams.cap_semanticscholar)||0, doaj: parseInt(inputParams.cap_doaj)||0, base: parseInt(inputParams.cap_base)||0, lens: parseInt(inputParams.cap_lens)||0, sciencedirect: parseInt(inputParams.cap_sciencedirect)||0 };
  var __seenSrc = {}; var __kept = [];
  for (var __i = 0; __i < allItems.length; __i++) {
    var __a = allItems[__i]; var __s = __a._source || __a.source || ''; var __cap = __capMap[__s] || 0;
    if (__cap > 0) { __seenSrc[__s] = (__seenSrc[__s] || 0) + 1; if (__seenSrc[__s] > __cap) continue; }
    __kept.push(__a);
  }
  if (__kept.length !== allItems.length) { console.log('Per-source cap: ' + allItems.length + ' -> ' + __kept.length); allItems.length = 0; for (var __j = 0; __j < __kept.length; __j++) allItems.push(__kept[__j]); }
}

// Apply global cap (apres merge de toutes les sources)
// SEARCH_DEDUP_MERGE_v1 - dedup par DOI (sinon titre+annee) + fusion des champs (recupere l'abstract depuis la source qui l'a)
function __normDoi(d){ return String(d||'').toLowerCase().replace(/^https?:\/\/(dx\.)?doi\.org\//,'').replace(/\s+/g,'').trim(); }
function __normTitle(t){ return String(t||'').toLowerCase().replace(/[^a-z0-9]+/g,' ').replace(/\s+/g,' ').trim(); }
function __mergePair(a,b){
  var m = Object.assign({}, a);
  var keys=['title','journal','year','volume','issue','pages','doi','pmid','openalex_id','url'];
  for (var i=0;i<keys.length;i++){ var k=keys[i]; if((m[k]===undefined||m[k]===''||m[k]===null)&&b[k]) m[k]=b[k]; }
  var aa=(a.abstract||''), ba=(b.abstract||''); m.abstract=(ba.length>aa.length)?ba:aa;
  var aAuth=Array.isArray(a.authors)?a.authors:[], bAuth=Array.isArray(b.authors)?b.authors:[];
  m.authors=(bAuth.length>aAuth.length)?bAuth:aAuth;
  var srcs={}; [].concat(a._merged_sources||[a._source||a.source||''], b._merged_sources||[b._source||b.source||'']).forEach(function(s){ if(s) srcs[s]=1; });
  m._merged_sources=Object.keys(srcs);
  return m;
}
var __byKey={}, __noKey=[], __order=[];
for (var __i=0; __i<allItems.length; __i++){
  var __a=allItems[__i];
  var __doi=__normDoi(__a.doi); var __ti=__normTitle(__a.title);
  var __key = __doi ? ('doi:'+__doi) : (__ti ? ('ti:'+__ti+'|'+(__a.year||'')) : '');
  if (!__key){ __noKey.push(__a); continue; }
  if (__byKey[__key]){ __byKey[__key]=__mergePair(__byKey[__key], __a); } else { __byKey[__key]=__a; __order.push(__key); }
}
var __deduped = __order.map(function(k){ return __byKey[k]; }).concat(__noKey);
var __dupRemoved = allItems.length - __deduped.length;
console.log('Search dedup+merge: '+allItems.length+' -> '+__deduped.length+' ('+__dupRemoved+' doublons fusionnes)');
let articles = __deduped;
if (!unlimited && capGlobal > 0 && articles.length > capGlobal) {
  console.log(`Apply cap_global ${capGlobal} on ${articles.length} -> ${capGlobal}`);
  articles = articles.slice(0, capGlobal);
}

// ABSTRACT_ENRICH_S2_v1 - enrichit les abstracts manquants via Semantic Scholar batch (par DOI ; OpenAlex/Crossref ne renvoient pas l'abstract par DOI, S2 oui)
var __absEnriched = 0;
try {
  var __needAbs = articles.filter(function(a){ return a.doi && (!a.abstract || a.abstract.length < 20); });
  if (__needAbs.length > 0) {
    var __s2key = '';
    try { var __kk = await this.helpers.httpRequest({ method: 'GET', url: 'http://host.docker.internal:8080/api/get-secret?field=semanticscholar_api_key', timeout: 5000, json: true }); __s2key = (__kk && __kk.value) || ''; } catch (e) {}
    var __toEnrich = __needAbs.slice(0, 1000);
    for (var __b = 0; __b < __toEnrich.length; __b += 500) {
      var __chunk = __toEnrich.slice(__b, __b + 500);
      var __ids = __chunk.map(function(a){ return 'DOI:' + __normDoi(a.doi); });
      var __hdr = { 'Content-Type': 'application/json' };
      if (__s2key) __hdr['x-api-key'] = __s2key;
      try {
        var __resp = await this.helpers.httpRequest({ method: 'POST', url: 'https://api.semanticscholar.org/graph/v1/paper/batch?fields=abstract', headers: __hdr, body: JSON.stringify({ ids: __ids }), timeout: 90000, json: true });
        if (Array.isArray(__resp)) {
          for (var __r = 0; __r < __resp.length; __r++) {
            var __it = __resp[__r];
            if (__it && __it.abstract && __chunk[__r] && (!__chunk[__r].abstract || __chunk[__r].abstract.length < 20)) {
              __chunk[__r].abstract = __it.abstract;
              __chunk[__r]._abstract_enriched = 'semanticscholar';
              __absEnriched++;
            }
          }
        }
      } catch (e) { console.log('S2 enrich batch error: ' + (e && e.message ? e.message : e)); }
      await new Promise(function(r){ setTimeout(r, __s2key ? 200 : 1100); });
    }
    // ABSTRACT_ENRICH_OA_v1 - fallback OpenAlex (abstract_inverted_index) pour le reste
    function __recon(inv){ if(!inv) return ''; var w=[]; for(var k in inv){ var ps=inv[k]; for(var i=0;i<ps.length;i++){ w[ps[i]]=k; } } return w.join(' ').replace(/\s+/g,' ').trim().substring(0,3000); }
    var __stillOA = __needAbs.filter(function(a){ return a.doi && (!a.abstract || a.abstract.length < 20); });
    for (var __o = 0; __o < Math.min(__stillOA.length, 1000); __o += 50) {
      var __chO = __stillOA.slice(__o, __o + 50);
      var __doisO = __chO.map(function(a){ return __normDoi(a.doi); }).filter(Boolean);
      if (!__doisO.length) continue;
      try {
        var __ro = await this.helpers.httpRequest({ method:'GET', url:'https://api.openalex.org/works?filter=doi:' + __doisO.join('|') + '&per_page=50&select=doi,abstract_inverted_index&mailto=ultralab-review@systematic-review.org', timeout: 60000, json: true });
        if (__ro && __ro.results) {
          var __byDoi = {};
          __ro.results.forEach(function(w){ var dd = __normDoi((w.doi||'')); if (dd) __byDoi[dd] = __recon(w.abstract_inverted_index); });
          __chO.forEach(function(a){ var dd = __normDoi(a.doi); if ((!a.abstract || a.abstract.length<20) && __byDoi[dd]) { a.abstract = __byDoi[dd]; a._abstract_enriched = 'openalex'; __absEnriched++; } });
        }
      } catch (e) { console.log('OA enrich batch error: ' + (e && e.message ? e.message : e)); }
    }
    console.log('Abstract enrich (S2+OpenAlex): ' + __absEnriched + '/' + __needAbs.length + ' abstracts recuperes par DOI');
  }
} catch (e) { console.log('Abstract enrich error: ' + (e && e.message ? e.message : e)); }

const counts = { pubmed: 0, openalex: 0, crossref: 0, semanticscholar: 0, doaj: 0, base: 0, lens: 0, sciencedirect: 0, clinicaltrials: 0 };
for (const a of allItems) {
  if (counts[a._source || a.source] !== undefined) counts[a._source || a.source]++;
}

// Format MEDLINE one entry
function fmt(tag, value) {
  if (!value && value !== 0) return '';
  const v = String(value).replace(/\r/g, '').replace(/\n/g, ' ').trim();
  if (!v) return '';
  // MEDLINE format : 4 chars tag, " - ", value, continuation lines indented 6 spaces
  // For simplicity we don't wrap long lines (nbib parsers handle long lines).
  return tag.padEnd(4) + '- ' + v + '\n';
}

function toNbib(a) {
  let out = '';
  // PMID first if available
  if (a.pmid) out += fmt('PMID', a.pmid);
  out += fmt('OWN', 'NLM');
  out += fmt('STAT', 'MEDLINE');
  out += fmt('PT', 'Journal Article');
  // Title
  out += fmt('TI', a.title);
  // Authors
  if (Array.isArray(a.authors)) {
    for (const au of a.authors) {
      if (au) {
        out += fmt('FAU', au);
        // Build AU as "Surname FI" if possible (assume "First Last")
        const parts = au.trim().split(/\s+/);
        if (parts.length >= 2) {
          const last = parts[parts.length - 1];
          const initials = parts.slice(0, -1).map(p => p.charAt(0).toUpperCase()).join('');
          out += fmt('AU', last + ' ' + initials);
        } else {
          out += fmt('AU', au);
        }
      }
    }
  }
  // Journal info
  if (a.journal) {
    out += fmt('JT', a.journal);
    out += fmt('TA', a.journal);
  }
  if (a.volume) out += fmt('VI', a.volume);
  if (a.issue) out += fmt('IP', a.issue);
  if (a.pages) out += fmt('PG', a.pages);
  // Date
  if (a.year) out += fmt('DP', a.year);
  // Abstract
  if (a.abstract) out += fmt('AB', a.abstract);
  // IDs
  if (a.doi) {
    out += fmt('AID', a.doi + ' [doi]');
    out += fmt('LID', a.doi + ' [doi]');
  }
  if (a.openalex_id) out += fmt('LID', a.openalex_id + ' [openalex]');
  // Source tag (custom, mais utile pour traçabilite)
  out += fmt('SO', '[source:' + (a._source || a.source || '') + ']');
  return out + '\n';
}

const nbibContent = articles.map(toNbib).join('');

// Sauvegarde fichier
// output_folder vient du parametre user (ex: /desktop/MaRecherche)
// le volume docker mappe /desktop -> Desktop user
let outputFolder = (inputParams.output_folder || '/desktop').trim();
if (!outputFolder.startsWith('/desktop')) {
  // Securite : forcer dans /desktop pour eviter ecriture hors zone
  outputFolder = '/desktop';
}
try {
  if (!fs.existsSync(outputFolder)) fs.mkdirSync(outputFolder, { recursive: true });
} catch(e) {
  console.log('mkdir error: ' + e.message);
}

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').substring(0, 19);
const runFolder = path.join(outputFolder, 'ultralab-search-' + timestamp); // GROUP_OUTPUTS_v1 - tout dans un sous-dossier dedie
try { if (!fs.existsSync(runFolder)) fs.mkdirSync(runFolder, { recursive: true }); } catch (e) { console.log('mkdir runFolder error: ' + e.message); }
const filename = 'ultralab-search-' + timestamp + '.nbib';
const fullPath = path.join(runFolder, filename);

let saveSuccess = false;
let saveError = null;
try {
  fs.writeFileSync(fullPath, nbibContent, 'utf-8');
  saveSuccess = true;
  console.log('NBIB saved: ' + fullPath + ' (' + articles.length + ' articles, ' + nbibContent.length + ' bytes)');
} catch(e) {
  saveError = e.message;
  console.log('NBIB save error: ' + e.message);
}

// METHODS_LOG_v1 - log de reproductibilite (section Methodes d'une revue systematique)
  try {
    var __methods = {
      generated_at: new Date().toISOString(),
      tool: 'UltraLab', module: 'recherche-api',
      nbib_file: filename,
      search: {
        pubmed_equation: inputParams.pubmed_query || '',
        per_base_queries: {
          openalex: inputParams.openalex_query || '', crossref: inputParams.crossref_query || '',
          semanticscholar: inputParams.semanticscholar_query || '', doaj: inputParams.doaj_query || '',
          base: inputParams.base_query || '', lens: inputParams.lens_query || '', sciencedirect: inputParams.sciencedirect_query || ''
        },
        date_range: { start: inputParams.date_start || '', end: inputParams.date_end || '' },
        count_by_source: counts,
        raw_total_before_dedup: allItems.length,
        duplicates_merged: __dupRemoved,
        with_abstract: articles.filter(function(a){return a.abstract && a.abstract.length>0;}).length,
        abstracts_enriched: __absEnriched,
        total_after_dedup: articles.length
      }
    };
    fs.writeFileSync(path.join(runFolder, 'methods.json'), JSON.stringify(__methods, null, 2), 'utf-8');
    console.log('methods.json saved (reproductibilite)');
  } catch (e) { console.log('methods write error: ' + e.message); }

  return [{ json: {
  action: 'search',
  success: saveSuccess,
  file_path: fullPath,
  file_name: filename,
  output_folder: runFolder,
  bytes: nbibContent.length,
  total_articles: articles.length,
  duplicates_merged: __dupRemoved,
  with_abstract: articles.filter(function(a){return a.abstract && a.abstract.length>0;}).length,
  abstracts_enriched: __absEnriched,
  count_by_source: counts,
  capped: !unlimited && capGlobal > 0 && allItems.length > capGlobal,
  original_total: allItems.length,
  error: saveError
}}];

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_semanticscholar === false) return [{ json: { _source: 'semanticscholar', count: 0, _disabled_by_user: true } }];
// Semantic Scholar Count - compte rapide (limit=1, on lit total)
const input = $('Extract Params').first().json;
const query = encodeURIComponent(input.semanticscholar_query || input.openalex_query || input.pubmed_query || input.question || '');
const PROXY = 'http://host.docker.internal:3456';
// SEMANTIC_SCHOLAR_KEY_v1 - cle API optionnelle (x-api-key, appel direct car le proxy ne porte pas les headers)
let __ssKey = '';
try { const __k = await this.helpers.httpRequest({ method: 'GET', url: 'http://host.docker.internal:8080/api/get-secret?field=semanticscholar_api_key', timeout: 5000, json: true }); __ssKey = (__k && __k.value) || ''; } catch (e) {}
if (!query) return [{ json: { _source: 'semanticscholar', count: 0 } }];
try {
  const url = 'https://api.semanticscholar.org/graph/v1/paper/search?query=' + query + '&limit=1';
  const __opts = __ssKey ? { method: 'GET', url: url, headers: { 'x-api-key': __ssKey }, timeout: 30000, json: true }
                         : { method: 'GET', url: PROXY + '?url=' + encodeURIComponent(url), timeout: 30000, json: true };
  const resp = await this.helpers.httpRequest(__opts);
  const count = (resp && resp.total) || 0;
  return [{ json: { _source: 'semanticscholar', count: count } }];
} catch (e) {
  return [{ json: { _source: 'semanticscholar', count: 0, error: e.message } }];
}

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_doaj === false) return [{ json: { _source: 'doaj', count: 0, _disabled_by_user: true } }];
// PER_BASE_QUERY_v1
// DOAJ Count
const input = $('Extract Params').first().json;
const query = (input.doaj_query || input.openalex_query || input.pubmed_query || input.question || '').replace(/[*?~]/g, '').replace(/\s+/g, ' ').trim(); // DOAJ_NOWILDCARD_v1
const PROXY = 'http://host.docker.internal:3456';
if (!query) return [{ json: { _source: 'doaj', count: 0 } }];
try {
  const url = 'https://doaj.org/api/search/articles/' + encodeURIComponent(query) + '?pageSize=1';
  const resp = await this.helpers.httpRequest({
    method: 'GET', url: PROXY + '?url=' + encodeURIComponent(url), timeout: 30000, json: true
  });
  return [{ json: { _source: 'doaj', count: (resp && resp.total) || 0 } }];
} catch (e) {
  return [{ json: { _source: 'doaj', count: 0, error: e.message } }];
}

// BASE_TOGGLE_v1
if ((($input.all()[0] && $input.all()[0].json) || {}).enable_base === false) return [{ json: { _source: 'base', count: 0, _disabled_by_user: true } }];
// BASE_IP_TRANSPARENCY_v1
// BASE Count
const input = $('Extract Params').first().json;
const query = input.base_query || input.openalex_query || input.pubmed_query || input.question || '';
const PROXY = 'http://host.docker.internal:3456';
if (!query) return [{ json: { _source: 'base', count: 0 } }];
try {
  const url = 'https://api.base-search.net/cgi-bin/BaseHttpSearchInterface.fcgi?func=PerformSearch&query=' +
              encodeURIComponent(query) + '&hits=1&format=json';
  const resp = await this.helpers.httpRequest({
    method: 'GET', url: PROXY + '?url=' + encodeURIComponent(url), timeout: 30000, json: true
  });
